// Extract error details from the Error Trigger output
const execution = $json.execution || {};
const workflow = $json.workflow || {};

// Get error info
const errorMessage = execution.error?.message || 'Unknown error';
const errorDescription = execution.error?.description || '';
const errorStack = execution.error?.stack || '';
const errorNode = execution.lastNodeExecuted || 'Unknown node';

// Get workflow info
const workflowId = workflow.id || 'N/A';
const workflowName = workflow.name || 'Unknown workflow';

// Get execution info
const executionId = execution.id || 'N/A';
const executionMode = execution.mode || 'N/A';
const executionUrl = execution.url || '';
const retryOf = execution.retryOf || '';

// Timestamp
const timestamp = new Date().toLocaleString('nl-BE', {
  timeZone: 'Europe/Brussels',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
});

// Build the email subject
const subject = `[n8n ERROR] ${workflowName} - Failed at node: ${errorNode}`;

// Build the HTML email body
const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; margin: 0; padding: 0; background-color: #f4f4f7; }
    .container { max-width: 640px; margin: 20px auto; background-color: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.08); }
    .header { background-color: #d32f2f; color: #ffffff; padding: 24px 32px; }
    .header h1 { margin: 0; font-size: 22px; font-weight: 600; }
    .header p { margin: 6px 0 0 0; font-size: 14px; opacity: 0.9; }
    .content { padding: 28px 32px; color: #333333; }
    .section { margin-bottom: 24px; }
    .section-title { font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.5px; color: #888888; margin-bottom: 10px; border-bottom: 1px solid #eeeeee; padding-bottom: 6px; }
    .info-table { width: 100%; border-collapse: collapse; }
    .info-table td { padding: 8px 0; vertical-align: top; font-size: 14px; }
    .info-table td:first-child { font-weight: 600; color: #555555; width: 140px; white-space: nowrap; }
    .info-table td:last-child { color: #222222; }
    .error-box { background-color: #fef2f2; border: 1px solid #fecaca; border-left: 4px solid #d32f2f; border-radius: 4px; padding: 16px; margin-top: 8px; }
    .error-message { font-size: 15px; font-weight: 600; color: #b91c1c; margin-bottom: 8px; }
    .error-description { font-size: 13px; color: #7f1d1d; }
    .stack-trace { background-color: #1e1e1e; color: #d4d4d4; padding: 16px; border-radius: 4px; font-family: 'Courier New', monospace; font-size: 12px; line-height: 1.5; overflow-x: auto; white-space: pre-wrap; word-break: break-all; margin-top: 8px; max-height: 300px; }
    .btn { display: inline-block; background-color: #d32f2f; color: #ffffff; text-decoration: none; padding: 10px 24px; border-radius: 4px; font-size: 14px; font-weight: 600; margin-top: 8px; }
    .btn:hover { background-color: #b71c1c; }
    .footer { background-color: #f9fafb; padding: 16px 32px; text-align: center; font-size: 12px; color: #9ca3af; border-top: 1px solid #e5e7eb; }
    .badge { display: inline-block; padding: 2px 10px; border-radius: 12px; font-size: 12px; font-weight: 600; }
    .badge-error { background-color: #fef2f2; color: #b91c1c; border: 1px solid #fecaca; }
    .badge-mode { background-color: #eff6ff; color: #1d4ed8; border: 1px solid #bfdbfe; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>&#9888; Workflow Execution Failed</h1>
      <p>${workflowName}</p>
    </div>
    <div class="content">

      <div class="section">
        <div class="section-title">Workflow Details</div>
        <table class="info-table">
          <tr><td>Workflow</td><td><strong>${workflowName}</strong></td></tr>
          <tr><td>Workflow ID</td><td>${workflowId}</td></tr>
          <tr><td>Execution ID</td><td>${executionId}</td></tr>
          <tr><td>Mode</td><td><span class="badge badge-mode">${executionMode}</span></td></tr>
          <tr><td>Failed Node</td><td><span class="badge badge-error">${errorNode}</span></td></tr>
          <tr><td>Timestamp</td><td>${timestamp}</td></tr>
          ${retryOf ? '<tr><td>Retry Of</td><td>' + retryOf + '</td></tr>' : ''}
        </table>
      </div>

      <div class="section">
        <div class="section-title">Error Details</div>
        <div class="error-box">
          <div class="error-message">${errorMessage}</div>
          ${errorDescription ? '<div class="error-description">' + errorDescription + '</div>' : ''}
        </div>
      </div>

      ${errorStack ? '<div class="section"><div class="section-title">Stack Trace</div><div class="stack-trace">' + errorStack.replace(/</g, '&lt;').replace(/>/g, '&gt;') + '</div></div>' : ''}

      ${executionUrl ? '<div class="section"><a href="' + executionUrl + '" class="btn">View Execution in n8n</a></div>' : ''}

    </div>
    <div class="footer">
      <p>This is an automated error notification from n8n &bull; Data Forge</p>
      <p>Sent to support@data-forge.be</p>
    </div>
  </div>
</body>
</html>
`;

// Build plain text version for email clients that don't support HTML
const textBody = [
  '=== N8N WORKFLOW ERROR ===' ,
  '',
  'WORKFLOW DETAILS',
  `  Workflow: ${workflowName}`,
  `  Workflow ID: ${workflowId}`,
  `  Execution ID: ${executionId}`,
  `  Mode: ${executionMode}`,
  `  Failed Node: ${errorNode}`,
  `  Timestamp: ${timestamp}`,
  retryOf ? `  Retry Of: ${retryOf}` : '',
  '',
  'ERROR DETAILS',
  `  Message: ${errorMessage}`,
  errorDescription ? `  Description: ${errorDescription}` : '',
  '',
  errorStack ? 'STACK TRACE' : '',
  errorStack ? errorStack : '',
  '',
  executionUrl ? `View execution: ${executionUrl}` : '',
  '',
  '---',
  'Automated error notification from n8n - Data Forge'
].filter(line => line !== '').join('\n');

return {
  subject,
  htmlBody,
  textBody,
  errorMessage,
  errorNode,
  workflowName,
  workflowId,
  executionId,
  executionMode,
  timestamp
};

// Log that this is a repeated failure (retry also failed)
const execution = $input.first().json.execution || {};
const workflow = $input.first().json.workflow || {};

const workflowName = workflow.name || 'Unknown';
const executionId = execution.id || 'N/A';
const retryOf = execution.retryOf || 'N/A';

const timestamp = new Date().toLocaleString('nl-BE', {
  timeZone: 'Europe/Brussels'
});

return {
  subject: `[n8n CRITICAL] ${workflowName} - Retry also failed!`,
  htmlBody: `
    <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">
      <div style="background: #7f1d1d; color: white; padding: 20px; border-radius: 8px 8px 0 0;">
        <h2 style="margin:0;">&#128680; CRITICAL: Retry Failed</h2>
      </div>
      <div style="padding: 20px; background: #fff; border: 1px solid #ddd; border-radius: 0 0 8px 8px;">
        <p>A retry execution for workflow <strong>${workflowName}</strong> has also failed.</p>
        <p><strong>Current Execution:</strong> ${executionId}</p>
        <p><strong>Original Execution:</strong> ${retryOf}</p>
        <p><strong>Time:</strong> ${timestamp}</p>
        <p style="color: #b91c1c; font-weight: bold;">This issue requires immediate attention as automatic retry did not resolve the problem.</p>
      </div>
    </div>
  `
};
